def find_hcf(a, b):
    if b == 0:
        return a
    return find_hcf(b, a % b)

print(find_hcf(48, 18))   # 6

def find_hcf(a, b):
    hcf = 1
    for i in range(1, min(a, b) + 1):
        if a % i == 0 and b % i == 0:
            hcf = i
    return hcf

print(find_hcf(48, 18))   # 6

def find_lcm(a, b):
    greater = max(a, b)
    while True:
        if greater % a == 0 and greater % b == 0:
            return greater
        greater += 1

print(find_lcm(48, 18))   # 144

def find_hcf(a, b):
